func (a *Adapter) CreateMeter(ctx context.Context, input meterpkg.CreateMeterInput) (meterpkg.Meter, error) {
	if err := input.Validate(); err != nil { return meterpkg.Meter{}, err }
	return transaction.Run(ctx, a, func(ctx context.Context) (meterpkg.Meter, error) {
		return entutils.TransactingRepo(ctx, a, func(ctx context.Context, repo *Adapter) (meterpkg.Meter, error) {
			entity, err := repo.db.Meter.Create().SetNamespace(input.Namespace).SetKey(input.Key).Save(ctx)
			if err != nil {
				if db.IsConstraintError(err) { return meterpkg.Meter{}, models.NewGenericConflictError(fmt.Errorf("meter with the same slug already exists")) }
				return meterpkg.Meter{}, fmt.Errorf("failed to create meter: %w", err)
			}
			return MapFromEntityFactory(entity)
		})
	})
}

func (h *handler) QueryMeterPost() QueryMeterPostHandler {
	return httptransport.NewHandlerWithArgs(
		func(ctx context.Context, r *http.Request, idOrSlug QueryMeterPostParams) (QueryMeterPostRequest, error) {
			ns, err := h.resolveNamespace(ctx)
			if err != nil { return QueryMeterPostRequest{}, err }
			var body api.QueryMeterPostJSONRequestBody
			if err := commonhttp.JSONRequestBodyDecoder(r, &body); err != nil { return QueryMeterPostRequest{}, err }
			return QueryMeterPostRequest{namespace: ns, idOrSlug: idOrSlug, params: body}, nil
		},
		func(ctx context.Context, req QueryMeterPostRequest) (QueryMeterPostResponse, error) {
			m, err := h.meterService.GetMeterByIDOrSlug(ctx, meter.GetMeterInput{Namespace: req.namespace, IDOrSlug: req.idOrSlug})
			if err != nil { return nil, err }
			params, err := h.toQueryParamsFromRequest(ctx, m, req.params)
			if err != nil { return nil, err }
			rows, err := h.streaming.QueryMeter(ctx, req.namespace, m, params)
			if err != nil { return nil, err }
			resp := ToAPIMeterQueryResult(req.params.From, req.params.To, req.params.WindowSize, rows)
			return &resp, nil
		},
		commonhttp.JSONResponseEncoderWithStatus[QueryMeterPostResponse](http.StatusOK),
		httptransport.AppendOptions(h.options, httptransport.WithOperationName("queryMeterPost"))...,
	)
}

